import { cursor } from './stores/cursor';
import { difficulty } from './stores/difficulty';
import { gamePaused, gameWon } from './stores/game';
import { grid } from './stores/grid';
import { timer } from './stores/timer';
import { hints } from './stores/hints';
import { gameStore } from './gameStore';
import { userGrid } from './stores/grid';
import { candidates } from './stores/candidates';
import { SUDOKU_SIZE } from './constants';

/**
 * Start new game with a generated sudoku
 *
 * @param {('veryeasy' | 'easy' | 'medium' | 'hard')} diff - Difficulty
 */
export function startNew(diff) {
	difficulty.set(diff);
	grid.generate(diff);
	cursor.reset();
	timer.reset();
	hints.reset();
	
	// 初始化领域对象 Game
	// grid.generate 是异步的，需要等待 grid store 更新后同步到 gameStore
	// 这里使用订阅机制
	const unsubscribe = grid.subscribe($grid => {
		gameStore.initGame($grid);
		unsubscribe(); // 只执行一次
	});

	location.hash = '';
}

/**
 * Start new game with a custom sudoku
 *
 * @param {string} sencode - Sencode to decode
 */
export function startCustom(sencode) {
	difficulty.setCustom();
	grid.decodeSencode(sencode);
	cursor.reset();
	timer.reset();
	hints.reset();
	
	// 初始化领域对象 Game
	const unsubscribe = grid.subscribe($grid => {
		gameStore.initGame($grid);
		unsubscribe(); // 只执行一次
	});
}

/**
 * Pause the game
 */
export function pauseGame() {
	timer.stop();
	gamePaused.set(true);
}

/**
 * Resume (un-pause) the game
 */
export function resumeGame() {
	timer.start();
	gamePaused.set(false);
}

// 导出 gameStore 供 UI 组件使用
export { gameStore };

export default {
	startNew,
	startCustom,
	pause: pauseGame,
	resume: resumeGame,
	gameStore
};